// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
// PARSE NORTH STAR + MASTER TASK LIST
// Extracts north star content, completed tasks this week,
// open needle-movers, and domain counts
// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ

const nsBinary = $('S3: Get North Star').first().binary;
const mtlBinary = $('S3: Get Master Task List').first().binary;

function extractText(binaryObj) {
  const key = Object.keys(binaryObj || {})[0];
  if (!key || !binaryObj[key]?.data) return '';
  return Buffer.from(binaryObj[key].data, 'base64').toString('utf-8');
}

const nsContent = extractText(nsBinary);
const mtlContent = extractText(mtlBinary);

const AREA_EMOJI = { faith:'рџ™Џ', family:'рџ’’', business:'рџљЂ', consulting:'рџ’ј', work:'рџЏҐ', health:'рџ’Є', home:'рџЏ ', personal:'рџ¤–' };

// Compute date range for this week (last 7 days)
const TZ = 'America/Chicago';
const now = new Date();
const fmt = (opts) => new Intl.DateTimeFormat('en-US', { timeZone: TZ, ...opts });
const y = parseInt(fmt({ year: 'numeric' }).format(now));
const mo = fmt({ month: '2-digit' }).format(now);
const d = fmt({ day: '2-digit' }).format(now);
const todayStr = `${y}-${mo}-${d}`;
const weekAgo = new Date(now.getTime() - 7 * 86400000);
const weekAgoStr = weekAgo.toISOString().split('T')[0];

// Parse open Priority A tasks (needle-movers)
const openTaskRx = /^\s*- \[ \]\s+(.+)$/gm;
const areaRx = /\[area::\s*(\w+)\s*\]/;
const priorityRx = /\[priority::\s*A\s*\]/i;
const dueRx = /\[due::\s*(\d{4}-\d{2}-\d{2})\s*\]/;

const openNeedleMovers = [];
const domainCounts = { faith:0, family:0, business:0, consulting:0, work:0, health:0, home:0, personal:0 };
let taskMatch;
openTaskRx.lastIndex = 0;

while ((taskMatch = openTaskRx.exec(mtlContent)) !== null) {
  const line = taskMatch[1];
  const areaMatch = line.match(areaRx);
  const area = areaMatch ? areaMatch[1] : 'personal';
  if (domainCounts[area] !== undefined) domainCounts[area]++;

  if (priorityRx.test(line)) {
    const dueMatch = line.match(dueRx);
    const cleanTitle = line.replace(/\[[^\]]+::[^\]]+\]/g, '').trim();
    openNeedleMovers.push({ task: cleanTitle, area, due: dueMatch ? dueMatch[1] : null });
  }
}

// Parse completed tasks this week (- [x] tasks)
const completedRx = /^\s*- \[x\]\s+(.+)$/gmi;
const completedThisWeekArr = [];
completedRx.lastIndex = 0;
while ((taskMatch = completedRx.exec(mtlContent)) !== null) {
  const line = taskMatch[1];
  const areaMatch = line.match(areaRx);
  const area = areaMatch ? areaMatch[1] : 'personal';
  const cleanTitle = line.replace(/\[[^\]]+::[^\]]+\]/g, '').trim();
  completedThisWeekArr.push({ task: cleanTitle, area });
}

const nmStr = openNeedleMovers.map(t => `- ${t.task} (${t.area}${t.due ? ', due ' + t.due : ''})`).join('\n') || 'None';
const completedStr = completedThisWeekArr.map(t => `- ${t.task} (${t.area})`).join('\n') || 'None';

return [{ json: {
  northStarContent: nsContent,
  openNeedleMovers: nmStr,
  completedThisWeek: completedStr,
  domainCounts,
  todayStr,
  openNeedleMoverCount: openNeedleMovers.length,
  completedCount: completedThisWeekArr.length
} }];

const input = $input.first().json;

const SYSTEM = 'You are the AI Brain for Aaron's Life Operating System. Return structured JSON only. Be honest, direct, and strategic. The weekly review is the most important output you produce.';

const USER = `TASK: Generate a strategic weekly review.

Analyze domain balance, needle-mover progress, and alignment between actions and stated goals. Be honest вЂ” if Aaron is ignoring a priority area, call it out. The "honest_question" should be genuinely challenging, not soft.

Return JSON:
{"results": {"needle_mover_scorecard": {"completed": [{"task": "string", "area": "string"}], "still_open": [{"task": "string", "area": "string", "next_action": "string"}], "completed_count": 0, "total_count": 0}, "domain_balance": {"faith": 0, "family": 0, "business": 0, "consulting": 0, "work": 0, "health": 0, "home": 0, "personal": 0}, "domain_warning": "string|null", "wins": ["string"], "next_week_focus": ["string", "string", "string"], "honest_question": "string"}}

NORTH STAR & QUARTERLY ROCKS:
${input.northStarContent}

COMPLETED TASKS THIS WEEK:
${input.completedThisWeek}

OPEN NEEDLE-MOVERS (Priority A):
${input.openNeedleMovers}

DOMAIN TASK COUNTS THIS WEEK:
${JSON.stringify(input.domainCounts)}`;

return [{ json: { systemPrompt: SYSTEM, userMessage: USER } }];

const input = $input.first().json;
try {
  const content = input.choices[0].message.content;
  // Strip markdown fences if present (some models add them)
  const cleaned = content.replace(/^```json\n?/i, '').replace(/\n?```$/i, '').trim();
  const parsed = JSON.parse(cleaned);
  return [{ json: { success: true, ...parsed, source: 'openrouter' } }];
} catch (e) {
  return [{ json: { success: false, error: 'Failed to parse AI response: ' + e.message, raw: JSON.stringify(input).substring(0, 500) } }];
}

const input = $input.first().json;
const r = input.results || {};
const sc = r.needle_mover_scorecard || { completed: [], still_open: [], completed_count: 0, total_count: 0 };
const db = r.domain_balance || {};

const areaEmoji = { faith: 'рџ™Џ', family: 'рџ’’', business: 'рџљЂ', consulting: 'рџ’ј', work: 'рџЏҐ', health: 'рџ’Є', home: 'рџЏ ', personal: 'рџ¤–' };

// Build domain balance bar chart
const maxCount = Math.max(...Object.values(db), 1);
const domainBar = (area, count) => {
  const barWidth = Math.round((count / maxCount) * 200);
  const emoji = areaEmoji[area] || 'рџ“Њ';
  const warning = count === 0 ? ' вљ пёЏ' : '';
  return `<tr><td style="padding:4px 8px;font-size:13px;">${emoji} ${area}</td><td style="padding:4px 8px;"><div style="background:#3498db;height:16px;width:${barWidth}px;border-radius:3px;display:inline-block;"></div> ${count}${warning}</td></tr>`;
};

let html = '<div style="font-family:-apple-system,BlinkMacSystemFont,\'Segoe UI\',Roboto,sans-serif;max-width:600px;margin:0 auto;">\n';
html += '<h1 style="color:#1a1a2e;">рџ“Љ Weekly Review</h1>\n';

// Needle-mover scorecard
html += `<h2 style="color:#2c3e50;">рџЋЇ Needle-Mover Scorecard: ${sc.completed_count} of ${sc.total_count}</h2>\n`;
if (sc.completed && sc.completed.length > 0) {
  html += '<ul style="list-style:none;padding:0;">' + sc.completed.map(t => `<li style="margin-bottom:4px;">вњ… ${t.task} (${t.area})</li>`).join('') + '</ul>\n';
}
if (sc.still_open && sc.still_open.length > 0) {
  html += '<ul style="list-style:none;padding:0;">' + sc.still_open.map(t => `<li style="margin-bottom:4px;">в¬њ ${t.task} (${t.area}) в†’ ${t.next_action}</li>`).join('') + '</ul>\n';
}

// Domain balance
html += '<h2 style="color:#2c3e50;">вљ–пёЏ Domain Balance</h2>\n';
html += '<table style="width:100%;border-collapse:collapse;">';
for (const area of ['work', 'consulting', 'business', 'family', 'faith', 'health', 'home', 'personal']) {
  html += domainBar(area, db[area] || 0);
}
html += '</table>\n';
if (r.domain_warning) {
  html += `<p style="color:#c0392b;font-weight:bold;">вљ пёЏ ${r.domain_warning}</p>\n`;
}

// Wins
if (r.wins && r.wins.length > 0) {
  html += '<h2 style="color:#27ae60;">рџЏ† Wins</h2>\n';
  html += '<ul>' + r.wins.map(w => `<li>${w}</li>`).join('') + '</ul>\n';
}

// Next week focus
if (r.next_week_focus && r.next_week_focus.length > 0) {
  html += '<h2 style="color:#8e44ad;">рџЋЇ Next Week Focus</h2>\n';
  html += '<ol>' + r.next_week_focus.map(f => `<li>${f}</li>`).join('') + '</ol>\n';
}

// Honest question
if (r.honest_question) {
  html += `<div style="background:#f8f9fa;border-left:4px solid #e74c3c;padding:16px;margin:20px 0;border-radius:4px;">\n`;
  html += `<h2 style="color:#e74c3c;margin-top:0;">рџ’¬ One Honest Question</h2>\n`;
  html += `<p style="font-style:italic;font-size:15px;color:#333;">"${r.honest_question}"</p>\n`;
  html += `</div>\n`;
}

html += '</div>';

const subject = `Weekly Review вЂ” ${sc.completed_count}/${sc.total_count} Needle-Movers Done${r.domain_warning ? ' | вљ пёЏ ' + r.domain_warning.substring(0, 40) : ''}`;

return [{ json: { subject, html } }];
